advertiser_id = #{search.memberId}

    AND (
        headline ILIKE '%' || #{search.keyword} || '%'
        OR (
        title ILIKE '%' || #{search.keyword} || '%'
        AND NOT (headline ILIKE '%' || #{search.keyword} || '%')
        )
    )



        AND status = 'active'


        AND status = 'reported'
